import { createChart } from './createChart';
import type {
  IChartApi,
  IChartManager,
  ChartApiOptions,
  ChartManagerOptions,
} from './IChartApi';

type ChartFactory = (container: HTMLElement, options?: ChartApiOptions) => IChartApi;

export class ChartSlotPool {
  private readonly free: number[] = [];
  private next = 0;

  acquire(): number {
    if (this.free.length > 0) {
      return this.free.pop() as number;
    }
    const slot = this.next;
    this.next += 1;
    return slot;
  }

  release(slot: number): void {
    if (!Number.isInteger(slot) || slot < 0) return;
    for (let i = 0; i < this.free.length; i++) {
      if (this.free[i] === slot) return;
    }
    this.free.push(slot);
  }
}

/**
 * マルチチャートマネージャーを作成する。
 *
 * 現行実装 (Canvas Core path) では各チャートは独立した ChartCore インスタンス。
 * WebGPU path (Phase 3) では 1 GPUDevice + 1 Data Worker + 1 Render Worker を
 * 共有し、N チャートのメモリ効率を最大化する。
 *
 * API は共通 — バックエンドが WebGPU になっても呼び出し側コードの変更は不要。
 */
export function createChartManagerWithFactory(
  options: ChartManagerOptions | undefined,
  createChartFn: ChartFactory,
): IChartManager {
  const maxCharts = options?.maxCharts ?? 16;
  const _charts = new Map<IChartApi, number>();
  const slots = new ChartSlotPool();
  const sharedDataWorker = options?.sharedDataWorker ?? options?.createDataWorker?.();
  const sharedRenderWorker = options?.sharedRenderWorker ?? options?.createRenderWorker?.();
  const ownsRenderWorker = options?.sharedRenderWorker == null && sharedRenderWorker != null;

  return {
    createChart(container: HTMLElement, chartOptions?: ChartApiOptions): IChartApi {
      if (_charts.size >= maxCharts) {
        throw new Error(`MochartManager: max ${maxCharts} charts exceeded`);
      }

      const slot = slots.acquire();
      const mergedOptions: ChartApiOptions = {
        ...(chartOptions ?? {}),
        managerSlotId: slot,
      };
      if (sharedDataWorker) {
        mergedOptions.dataWorker = sharedDataWorker;
      }
      if (sharedRenderWorker) {
        mergedOptions.sharedRenderWorker = sharedRenderWorker;
        if (!mergedOptions.renderer) {
          mergedOptions.renderer = 'canvas-worker';
        }
      }

      const chart = createChartFn(container, mergedOptions);
      _charts.set(chart, slot);
      return chart;
    },

    destroyChart(chart: IChartApi): void {
      const slot = _charts.get(chart);
      if (slot == null) return;
      _charts.delete(chart);
      slots.release(slot);
      chart.destroy();
    },

    destroyAll(): void {
      for (const [chart, slot] of _charts.entries()) {
        slots.release(slot);
        chart.destroy();
      }
      _charts.clear();
      if (ownsRenderWorker) {
        sharedRenderWorker.terminate();
      }
    },

    get activeCount(): number {
      return _charts.size;
    },
  };
}

export function createChartManager(options?: ChartManagerOptions): IChartManager {
  return createChartManagerWithFactory(options, createChart as unknown as ChartFactory);
}
