import type {
  Annotation,
  AnnotationHandle,
  TradeRecord,
  TradeRecordDisplayOptions,
  RGBA,
} from '../IChartApi';
import type { OverlayRenderPrimitive } from '../../renderer/renderer';
import { buildHudOverlaySnapshot, type HudOverlaySnapshot } from './hudPainter';

const DEFAULT_ENTRY_COLOR: RGBA = [0, 0.8, 0.2, 1];
const DEFAULT_EXIT_COLOR: RGBA = [0.9, 0.2, 0.2, 1];
const DEFAULT_PROFIT_ZONE: RGBA = [0, 0.8, 0.2, 0.08];
const DEFAULT_LOSS_ZONE: RGBA = [0.9, 0.2, 0.2, 0.08];
const DEFAULT_SL_COLOR: RGBA = [0.9, 0.2, 0.2, 0.8];
const DEFAULT_TP_COLOR: RGBA = [0, 0.8, 0.2, 0.8];

function rgbaToCss(color: RGBA | undefined): string | undefined {
  if (!color) return undefined;
  const r = Math.max(0, Math.min(255, Math.floor(color[0] * 255)));
  const g = Math.max(0, Math.min(255, Math.floor(color[1] * 255)));
  const b = Math.max(0, Math.min(255, Math.floor(color[2] * 255)));
  const a = Math.max(0, Math.min(1, color[3]));
  return `rgba(${r},${g},${b},${a})`;
}

function expandTradeRecords(
  trades: TradeRecord[],
  opts: TradeRecordDisplayOptions = {},
): Annotation[] {
  const showMarkers = opts.showMarkers !== false;
  const showSlTpLines = opts.showSlTpLines !== false;
  const showZones = opts.showZones !== false;
  const showPnl = opts.showPnlLabels !== false;
  const showConf = opts.showConfidence === true;
  const entryColor = opts.entryColor ?? DEFAULT_ENTRY_COLOR;
  const exitColor = opts.exitColor ?? DEFAULT_EXIT_COLOR;
  const profitZone = opts.profitZoneColor ?? DEFAULT_PROFIT_ZONE;
  const lossZone = opts.lossZoneColor ?? DEFAULT_LOSS_ZONE;

  const out: Annotation[] = [];

  for (let i = 0; i < trades.length; i++) {
    const t = trades[i];
    const prefix = `trade_${i}`;

    if (showMarkers) {
      out.push({
        type: 'marker',
        id: `${prefix}_entry`,
        time: t.entryTime,
        price: t.entryPrice,
        shape: 'arrow_up',
        color: entryColor,
        label: t.strategy ?? t.label,
      });
    }

    if (showMarkers && t.exitTime != null && t.exitPrice != null) {
      out.push({
        type: 'marker',
        id: `${prefix}_exit`,
        time: t.exitTime,
        price: t.exitPrice,
        shape: 'arrow_down',
        color: exitColor,
        label: t.exitReason,
      });

      if (showPnl && t.pnl != null) {
        const pctStr = t.pnlPercent != null ? ` (${t.pnlPercent > 0 ? '+' : ''}${t.pnlPercent.toFixed(1)}%)` : '';
        const sign = t.pnl >= 0 ? '+' : '';
        out.push({
          type: 'text',
          id: `${prefix}_pnl`,
          time: t.exitTime,
          price: t.exitPrice,
          text: `${sign}$${Math.abs(t.pnl).toFixed(0)}${pctStr}`,
          color: t.pnl >= 0 ? entryColor : exitColor,
          anchor: 'bottom',
          fontSize: 10,
        });
      }
    }

    if (showSlTpLines && t.exitTime != null) {
      if (t.stopLoss != null) {
        out.push({
          type: 'hline',
          id: `${prefix}_sl`,
          time: t.entryTime,
          timeEnd: t.exitTime,
          price: t.stopLoss,
          color: DEFAULT_SL_COLOR,
          dash: [4, 4],
          label: 'SL',
        });
      }
      if (t.takeProfit != null) {
        out.push({
          type: 'hline',
          id: `${prefix}_tp`,
          time: t.entryTime,
          timeEnd: t.exitTime,
          price: t.takeProfit,
          color: DEFAULT_TP_COLOR,
          dash: [4, 4],
          label: 'TP',
        });
      }
    }

    if (showZones && t.exitTime != null && t.exitPrice != null) {
      const lo = Math.min(t.entryPrice, t.exitPrice);
      const hi = Math.max(t.entryPrice, t.exitPrice);
      const isProfit = t.pnl != null ? t.pnl >= 0 : t.exitPrice >= t.entryPrice;
      out.push({
        type: 'zone',
        id: `${prefix}_zone`,
        time: t.entryTime,
        timeEnd: t.exitTime,
        price: lo,
        priceEnd: hi,
        color: isProfit ? profitZone : lossZone,
      });
    }

    if (showConf && t.confidence != null) {
      out.push({
        type: 'text',
        id: `${prefix}_conf`,
        time: t.entryTime,
        price: t.entryPrice,
        text: `conf: ${t.confidence.toFixed(2)}`,
        color: [1, 1, 1, 0.8],
        fontSize: 9,
        anchor: 'top',
        bgColor: [0.2, 0.2, 0.2, 0.7],
      });
    }
  }

  return out;
}

export interface OverlayController {
  addAnnotation: (annotation: Annotation) => AnnotationHandle;
  addAnnotations: (annotations: Annotation[]) => AnnotationHandle[];
  updateAnnotation: (id: string, patch: Record<string, unknown>) => void;
  removeAnnotation: (id: string) => void;
  clearAnnotations: () => void;
  getAnnotations: () => readonly Annotation[];
  getOverlayRevision: () => number;
  getOverlayPrimitives: () => readonly OverlayRenderPrimitive[];
  getHudSnapshot: () => Readonly<HudOverlaySnapshot>;
  setTradeRecords: (trades: TradeRecord[], displayOptions?: TradeRecordDisplayOptions) => void;
  clearTradeRecords: () => void;
}

export function createOverlayController(nextAnnotationId: () => string): OverlayController {
  const annotations = new Map<string, Annotation>();
  let tradeAnnotationIds: string[] = [];
  let hudSnapshot: HudOverlaySnapshot = buildHudOverlaySnapshot([]);
  let overlayRevision = 0;

  const rebuildHudSnapshot = (): void => {
    const values: Annotation[] = [];
    for (const value of annotations.values()) values.push(value);
    hudSnapshot = buildHudOverlaySnapshot(values);
    overlayRevision += 1;
  };

  const buildOverlayPrimitives = (): OverlayRenderPrimitive[] => {
    const primitives: OverlayRenderPrimitive[] = [];
    for (const ann of annotations.values()) {
      if (!ann.id) continue;
      if (ann.type === 'marker') {
        primitives.push({
          type: 'marker',
          id: ann.id,
          time: ann.time,
          price: ann.price,
          shape: ann.shape,
          color: ann.color,
          colorCss: rgbaToCss(ann.color),
        });
        continue;
      }
      if (ann.type === 'hline') {
        primitives.push({
          type: 'hline',
          id: ann.id,
          time: ann.time,
          timeEnd: ann.timeEnd,
          price: ann.price,
          color: ann.color,
          colorCss: rgbaToCss(ann.color),
          dash: ann.dash,
        });
        continue;
      }
      if (ann.type === 'zone') {
        primitives.push({
          type: 'zone',
          id: ann.id,
          time: ann.time,
          timeEnd: ann.timeEnd,
          price: ann.price,
          priceEnd: ann.priceEnd,
          color: ann.color,
          colorCss: rgbaToCss(ann.color),
        });
      }
    }
    return primitives;
  };

  const makeAnnotationHandle = (ann: Annotation): AnnotationHandle => {
    const id = ann.id ?? nextAnnotationId();
    const stored = { ...ann, id } as Annotation & { id: string };
    annotations.set(id, stored);
    return {
      id,
      update(patch: Record<string, unknown>) {
        const existing = annotations.get(id);
        if (!existing) return;
        Object.assign(existing, patch);
      },
      remove() {
        annotations.delete(id);
      },
    };
  };

  const clearTradeRecords = (): void => {
    for (let i = 0; i < tradeAnnotationIds.length; i++) {
      annotations.delete(tradeAnnotationIds[i]);
    }
    tradeAnnotationIds = [];
    rebuildHudSnapshot();
  };

  return {
    addAnnotation(annotation: Annotation) {
      const handle = makeAnnotationHandle(annotation);
      rebuildHudSnapshot();
      return handle;
    },

    addAnnotations(annotationsInput: Annotation[]) {
      const handles: AnnotationHandle[] = [];
      for (let i = 0; i < annotationsInput.length; i++) {
        handles.push(makeAnnotationHandle(annotationsInput[i]));
      }
      rebuildHudSnapshot();
      return handles;
    },

    updateAnnotation(id: string, patch: Record<string, unknown>) {
      const existing = annotations.get(id);
      if (!existing) return;
      Object.assign(existing, patch);
      rebuildHudSnapshot();
    },

    removeAnnotation(id: string) {
      annotations.delete(id);
      rebuildHudSnapshot();
    },

    clearAnnotations() {
      annotations.clear();
      tradeAnnotationIds = [];
      rebuildHudSnapshot();
    },

    getAnnotations() {
      const out: Annotation[] = [];
      for (const value of annotations.values()) out.push(value);
      return out;
    },

    getOverlayRevision() {
      return overlayRevision;
    },

    getOverlayPrimitives() {
      return buildOverlayPrimitives();
    },

    getHudSnapshot() {
      return hudSnapshot;
    },

    setTradeRecords(trades: TradeRecord[], displayOptions?: TradeRecordDisplayOptions) {
      clearTradeRecords();
      const expanded = expandTradeRecords(trades, displayOptions);
      tradeAnnotationIds = [];
      for (let i = 0; i < expanded.length; i++) {
        const handle = makeAnnotationHandle(expanded[i]);
        tradeAnnotationIds.push(handle.id);
      }
      rebuildHudSnapshot();
    },

    clearTradeRecords,
  };
}
