import type { Annotation } from '../IChartApi';
import initMochartWasmNew, { overlay_pack_std430_ptr, overlay_std430_layout_align, overlay_std430_layout_bytes } from '../../pkg/mochart_wasm_new.js';
import { fetchMochartWasmBytes } from '../../wasm/assetLocator';

const OVERLAY_STD430_WORDS = 8;
const OVERLAY_STD430_BYTES = OVERLAY_STD430_WORDS * 4;
const OVERLAY_STD430_ALIGN = 16;

const OVERLAY_KIND_MARKER = 1 << 0;
const OVERLAY_KIND_HLINE = 1 << 1;
const OVERLAY_KIND_ZONE = 1 << 2;
const OVERLAY_KIND_TEXT = 1 << 3;
const OVERLAY_KIND_EVENT = 1 << 4;

let overlayStatsReady = false;
let overlayStatsLoadStarted = false;
let overlayStatsLoadFailed = false;
let overlayStatsInitPromise: Promise<{ memory: WebAssembly.Memory }> | null = null;

let overlayStatsMemory: WebAssembly.Memory | null = null;
let overlayPackStd430PtrFn:
  | ((
      marker_count: number,
      hline_count: number,
      zone_count: number,
      text_count: number,
      event_count: number,
    ) => number)
  | null = null;

let overlayScratchWords: Uint32Array | null = null;
let overlayScratchBuffer: ArrayBufferLike | null = null;

export interface HudOverlaySnapshot {
  markerCount: number;
  hlineCount: number;
  zoneCount: number;
  textCount: number;
  eventCount: number;
  totalCount: number;
  kindMask: number;
}

function buildKindMask(
  markerCount: number,
  hlineCount: number,
  zoneCount: number,
  textCount: number,
  eventCount: number,
): number {
  let mask = 0;
  if (markerCount > 0) mask |= OVERLAY_KIND_MARKER;
  if (hlineCount > 0) mask |= OVERLAY_KIND_HLINE;
  if (zoneCount > 0) mask |= OVERLAY_KIND_ZONE;
  if (textCount > 0) mask |= OVERLAY_KIND_TEXT;
  if (eventCount > 0) mask |= OVERLAY_KIND_EVENT;
  return mask;
}

function startOverlayStatsLoad(): void {
  if (overlayStatsReady || overlayStatsLoadStarted || overlayStatsLoadFailed) {
    return;
  }
  overlayStatsLoadStarted = true;
  void loadOverlayStatsBindings();
}

async function loadOverlayStatsBindings(): Promise<void> {
  try {
    const wasmBytes = await fetchMochartWasmBytes('new');
    if (!overlayStatsInitPromise) {
      overlayStatsInitPromise = initMochartWasmNew({ module_or_path: wasmBytes }) as Promise<{ memory: WebAssembly.Memory }>;
    }
    const initOutput = await overlayStatsInitPromise;

    const layoutBytes = overlay_std430_layout_bytes();
    const layoutAlign = overlay_std430_layout_align();
    if (layoutBytes !== OVERLAY_STD430_BYTES || layoutAlign !== OVERLAY_STD430_ALIGN) {
      overlayStatsLoadFailed = true;
      return;
    }

    overlayStatsMemory = initOutput.memory;
    overlayPackStd430PtrFn = overlay_pack_std430_ptr;
    overlayStatsReady = true;
  } catch {
    overlayStatsInitPromise = null;
    overlayStatsLoadFailed = true;
  }
}

function tryReadPackedHudStats(
  markerCount: number,
  hlineCount: number,
  zoneCount: number,
  textCount: number,
  eventCount: number,
): { totalCount: number; kindMask: number } | null {
  if (!overlayStatsReady || !overlayStatsMemory || !overlayPackStd430PtrFn) {
    return null;
  }

  const ptr = overlayPackStd430PtrFn(markerCount, hlineCount, zoneCount, textCount, eventCount);
  if ((ptr & 3) !== 0) return null;

  const memoryBuffer = overlayStatsMemory.buffer;
  if (overlayScratchBuffer !== memoryBuffer) {
    overlayScratchWords = new Uint32Array(memoryBuffer);
    overlayScratchBuffer = memoryBuffer;
  }
  if (!overlayScratchWords) return null;

  const baseWord = ptr >>> 2;
  if (baseWord + OVERLAY_STD430_WORDS > overlayScratchWords.length) return null;

  const packedTotal = overlayScratchWords[baseWord];
  const packedMarker = overlayScratchWords[baseWord + 1];
  const packedHline = overlayScratchWords[baseWord + 2];
  const packedZone = overlayScratchWords[baseWord + 3];
  const packedText = overlayScratchWords[baseWord + 4];
  const packedEvent = overlayScratchWords[baseWord + 5];
  const packedMask = overlayScratchWords[baseWord + 6];

  // Guardrail: if bridge data is inconsistent, fail closed to deterministic TS fallback.
  if (
    packedMarker !== markerCount
    || packedHline !== hlineCount
    || packedZone !== zoneCount
    || packedText !== textCount
    || packedEvent !== eventCount
  ) {
    return null;
  }

  return {
    totalCount: packedTotal,
    kindMask: packedMask,
  };
}

// Keep HUD-related aggregation isolated from createChart; actual draw backends consume this later.
export function buildHudOverlaySnapshot(annotations: readonly Annotation[]): HudOverlaySnapshot {
  startOverlayStatsLoad();

  let markerCount = 0;
  let hlineCount = 0;
  let zoneCount = 0;
  let textCount = 0;
  let eventCount = 0;

  for (let i = 0; i < annotations.length; i++) {
    const ann = annotations[i];
    if (ann.type === 'marker') markerCount++;
    else if (ann.type === 'hline') hlineCount++;
    else if (ann.type === 'zone') zoneCount++;
    else if (ann.type === 'text') textCount++;
    else if (ann.type === 'event') eventCount++;
  }

  const fallbackTotal = markerCount + hlineCount + zoneCount + textCount + eventCount;
  const fallbackKindMask = buildKindMask(markerCount, hlineCount, zoneCount, textCount, eventCount);
  const packed = tryReadPackedHudStats(markerCount, hlineCount, zoneCount, textCount, eventCount);

  return {
    markerCount,
    hlineCount,
    zoneCount,
    textCount,
    eventCount,
    totalCount: packed?.totalCount ?? fallbackTotal,
    kindMask: packed?.kindMask ?? fallbackKindMask,
  };
}
