import type { OhlcvPoint } from '../core/types';
import { loadWasmModule } from './wasmModule';

type WasmRingBufferHandle = {
  len(): number;
  is_full(): boolean;
  clear(): void;
  push(time: number, open: number, high: number, low: number, close: number, volume: number): void;
  time(): Float64Array;
  open(): Float32Array;
  high(): Float32Array;
  low(): Float32Array;
  close(): Float32Array;
  volume(): Float32Array;
};

export interface WasmRingBuffer {
  push(point: OhlcvPoint): void;
  size(): number;
  isFull(): boolean;
  clear(): void;
  toArray(): readonly OhlcvPoint[];
}

export class NoopWasmRingBuffer implements WasmRingBuffer {
  private _items: OhlcvPoint[] = [];

  constructor(private readonly capacity = 2048) {}

  push(point: OhlcvPoint): void {
    if (this._items.length >= this.capacity) {
      this._items.shift();
    }
    this._items.push(point);
  }

  size(): number {
    return this._items.length;
  }

  isFull(): boolean {
    return this._items.length >= this.capacity;
  }

  clear(): void {
    this._items = [];
  }

  toArray(): readonly OhlcvPoint[] {
    return this._items;
  }
}

class WasmRingBufferImpl implements WasmRingBuffer {
  constructor(private readonly handle: WasmRingBufferHandle) {}

  push(point: OhlcvPoint): void {
    this.handle.push(point.time, point.open, point.high, point.low, point.close, point.volume);
  }

  size(): number {
    return this.handle.len();
  }

  isFull(): boolean {
    return this.handle.is_full();
  }

  clear(): void {
    this.handle.clear();
  }

  toArray(): readonly OhlcvPoint[] {
    const time = this.handle.time();
    const open = this.handle.open();
    const high = this.handle.high();
    const low = this.handle.low();
    const close = this.handle.close();
    const volume = this.handle.volume();
    const len = time.length;
    const out = new Array<OhlcvPoint>(len);
    for (let i = 0; i < len; i++) {
      out[i] = {
        time: time[i],
        open: open[i],
        high: high[i],
        low: low[i],
        close: close[i],
        volume: volume[i],
      };
    }
    return out;
  }
}

export async function createWasmRingBuffer(capacity = 2048): Promise<WasmRingBuffer> {
  const modResult = await loadWasmModule();
  if (!modResult) {
    return new NoopWasmRingBuffer(capacity);
  }
  const { bindings } = modResult;

  const wasmWithClasses = bindings as (typeof bindings & {
    WasmRingBuffer?: new (capacity: number) => WasmRingBufferHandle;
  }) | null;

  if (!wasmWithClasses || typeof wasmWithClasses.WasmRingBuffer !== 'function') {
    return new NoopWasmRingBuffer(capacity);
  }
  const handle = new wasmWithClasses.WasmRingBuffer(capacity);
  return new WasmRingBufferImpl(handle);
}
