import type { InitOutput } from '../pkg/mochart_wasm';
import { fetchMochartWasmBytes } from './assetLocator';

type WasmModuleBindings = typeof import('../pkg/mochart_wasm');

let wasmLoadPromise: Promise<{ bindings: WasmModuleBindings; instance: InitOutput } | null> | null =
  null;

async function tryImportModule(): Promise<{
  bindings: WasmModuleBindings;
  instance: InitOutput;
} | null> {
  try {
    const bindings = await import('../pkg/mochart_wasm');
    let instance: InitOutput;

    // init 関数がエクスポートされていれば必ず呼ぶ
    if (typeof bindings.default === 'function') {
      const wasmBytes = await fetchMochartWasmBytes('legacy');
      instance = await bindings.default({ module_or_path: wasmBytes });
    } else {
      // エッジケース: init がない/すでにロード済み? 通常はここに来ない
      return null;
    }

    // wasm_ready は存在すれば呼び出して確認するが、厳密に true を要求しない。
    // ここで失敗すると try/catch により null を返していたため、原因が不明瞭になっていた。
    try {
      if (typeof bindings.wasm_ready === 'function') {
        const ready = bindings.wasm_ready();
        if (ready !== true) {
          console.debug('[wasm] wasm_ready returned falsy:', ready);
        }
      }
    } catch (e) {
      console.warn('[wasm] wasm_ready threw:', e);
    }

    return { bindings, instance };
  } catch (e) {
    // 捕捉したエラーはブラウザコンソールに残すとデバッグが容易になる
    console.warn('[wasm] failed to import/initialize module', e instanceof Error ? e.message : e);
    if (e && (e as any).stack) console.debug('[wasm] stack', (e as any).stack);
    return null;
  }
}

export async function loadWasmModule() {
  if (!wasmLoadPromise) {
    wasmLoadPromise = tryImportModule();
  }
  return wasmLoadPromise;
}

export type WasmMochartBindings = WasmModuleBindings;
export type WasmMochartInitOutput = InitOutput;
