import type { OhlcvPoint } from '../core/types';
import { loadWasmModule } from './wasmModule';

export type WasmKernelAvailability = Readonly<{
  ready: boolean;
}>;

export type WasmIndicatorKernelId =
  | 'sma'
  | 'ema'
  | 'bollinger'
  | 'rsi'
  | 'macd'
  | 'atr'
  | 'obv'
  | 'mfi'
  | 'stochastic'
  | 'williams_r'
  | 'cci'
  | 'adx';

export type WasmIndicatorKernelInput = Readonly<{
  values?: Float32Array;
  high?: Float32Array;
  low?: Float32Array;
  close?: Float32Array;
  volume?: Float32Array;
  period?: number;
  stdDev?: number;
  fast?: number;
  slow?: number;
  signal?: number;
}>;

export async function getWasmKernelAvailability(): Promise<WasmKernelAvailability> {
  const modResult = await loadWasmModule();
  return { ready: modResult !== null };
}

export async function wasmMinMax(values: Float32Array): Promise<Float32Array | null> {
  const modResult = await loadWasmModule();
  if (!modResult) return null;
  const { bindings, instance } = modResult;
  // prefer ptr/len zero-copy path when possible
  if (typeof bindings.min_max_f32_ptr === 'function') {
    // if values already backed by wasm memory, call ptr-based entry
    if (values.buffer === instance.memory.buffer) {
      const ptr = values.byteOffset;
      const len = values.length;
      // shared_memory.min_max_f32_ptr expects (ptr, len)
      const res = bindings.min_max_f32_ptr(ptr, len);
      // wasm-bindgen may return a typed array or pointer; normalize
      if (res instanceof Float32Array) return res;
    }
  }
  return bindings.min_max_f32(values);
}

export async function wasmNearestIndex(times: Float64Array, target: number): Promise<number | null> {
  const modResult = await loadWasmModule();
  if (!modResult) return null;
  const { bindings } = modResult;
  return bindings.nearest_index(times, target);
}

export async function wasmLttbDownsample(
  times: Float64Array,
  values: Float32Array,
  threshold: number,
): Promise<Uint32Array | null> {
  const modResult = await loadWasmModule();
  if (!modResult) return null;
  const { bindings, instance } = modResult;
  if (typeof bindings.lttb_downsample_ptr === 'function') {
    if (values.buffer === instance.memory.buffer && times.buffer === instance.memory.buffer) {
      const ptrV = values.byteOffset;
      const lenV = values.length;
      const ptrT = times.byteOffset;
      const lenT = times.length;
      const outPtr = (bindings.lttb_downsample_ptr as unknown as (pT: number, lT: number, pV: number, lV: number, n: number) => number)(ptrT, lenT, ptrV, lenV, threshold);
      const outLen = bindings.lttb_downsample_len ? bindings.lttb_downsample_len() : 0;
      if (outPtr && outLen) return new Uint32Array(instance.memory.buffer, outPtr, outLen);
    }
  }
  return bindings.lttb_downsample(times, values, threshold);
}

export async function wasmRunIndicatorKernel(
  id: WasmIndicatorKernelId,
  input: WasmIndicatorKernelInput,
): Promise<Float32Array | null> {
  const modResult = await loadWasmModule();
  if (!modResult) return null;
  const { bindings } = modResult;

  switch (id) {
    case 'sma': {
      if (!input.values) return null;
      // prefer zero-copy path: some bindings expose sma_f32_ptr + sma_f32_len
      // Prefer explicit ptr/len entrypoints when the input is already in wasm memory.
      if (typeof bindings.sma_ptr === 'function' && (modResult as any).instance) {
        const { instance } = modResult as any;
        if (input.values.buffer === instance.memory.buffer) {
          const ptr = input.values.byteOffset;
          const len = input.values.length;
          const res = bindings.sma_ptr(ptr, len, input.period ?? 14);
          if (res instanceof Float32Array) return res;
          return res as Float32Array;
        }
      }
      // Fallbacks: wasm-bindgen helper that accepts TypedArray or copy-returning JS wrapper.
      if (typeof bindings.sma_f32_ptr === 'function' && typeof bindings.sma_f32_len === 'function') {
        if ((modResult as any).instance && input.values.buffer === (modResult as any).instance.memory.buffer) {
          const { instance } = modResult as any;
          const ptr = bindings.sma_f32_ptr(input.values, input.period ?? 14);
          const len = bindings.sma_f32_len();
          return new Float32Array(instance.memory.buffer, ptr, len);
        }
      }
      return bindings.sma_f32(input.values, input.period ?? 14);
    }
    case 'ema': {
      if (!input.values) return null;
      if (typeof bindings.ema_ptr === 'function' && (modResult as any).instance) {
        const { instance } = modResult as any;
        if (input.values.buffer === instance.memory.buffer) {
          const ptr = input.values.byteOffset;
          const len = input.values.length;
          const res = bindings.ema_ptr(ptr, len, input.period ?? 14);
          if (res instanceof Float32Array) return res;
          return res as Float32Array;
        }
      }
      if (typeof bindings.ema_f32_ptr === 'function' && typeof bindings.ema_f32_len === 'function') {
        if ((modResult as any).instance && input.values.buffer === (modResult as any).instance.memory.buffer) {
          const { instance } = modResult as any;
          const ptr = bindings.ema_f32_ptr(input.values, input.period ?? 14);
          const len = bindings.ema_f32_len();
          return new Float32Array(instance.memory.buffer, ptr, len);
        }
      }
      return bindings.ema_f32(input.values, input.period ?? 14);
    }
    case 'bollinger': {
      if (!input.values) return null;
      return bindings.bollinger_f32(input.values, input.period ?? 20, input.stdDev ?? 2);
    }
    case 'rsi': {
      if (!input.values) return null;
      return bindings.rsi_f32(input.values, input.period ?? 14);
    }
    case 'macd': {
      if (!input.values) return null;
      return bindings.macd_f32(input.values, input.fast ?? 12, input.slow ?? 26, input.signal ?? 9);
    }
    case 'atr': {
      if (!input.high || !input.low || !input.close) return null;
      return bindings.atr_f32(input.high, input.low, input.close, input.period ?? 14);
    }
    case 'obv': {
      if (!input.close || !input.volume) return null;
      return bindings.obv_f32(input.close, input.volume);
    }
    case 'mfi': {
      if (!input.high || !input.low || !input.close || !input.volume) return null;
      return bindings.mfi_f32(input.high, input.low, input.close, input.volume, input.period ?? 14);
    }
    case 'stochastic': {
      if (!input.high || !input.low || !input.close) return null;
      return bindings.stochastic_f32(input.high, input.low, input.close, input.period ?? 14);
    }
    case 'williams_r': {
      if (!input.high || !input.low || !input.close) return null;
      return bindings.williams_r_f32(input.high, input.low, input.close, input.period ?? 14);
    }
    case 'cci': {
      if (!input.high || !input.low || !input.close) return null;
      return bindings.cci_f32(input.high, input.low, input.close, input.period ?? 14);
    }
    case 'adx': {
      if (!input.high || !input.low || !input.close) return null;
      return bindings.adx_f32(input.high, input.low, input.close, input.period ?? 14);
    }
    default:
      return null;
  }
}

export function toColumnarInputs(data: readonly OhlcvPoint[]): {
  time: Float64Array;
  open: Float32Array;
  high: Float32Array;
  low: Float32Array;
  close: Float32Array;
  volume: Float32Array;
} {
  // Convert AoS OhlcvPoint[] to columnar TypedArrays (no instrumentation)
  {
    const len = data.length;
    const time = new Float64Array(len);
    const open = new Float32Array(len);
    const high = new Float32Array(len);
    const low = new Float32Array(len);
    const close = new Float32Array(len);
    const volume = new Float32Array(len);

    for (let i = 0; i < len; i++) {
      const point = data[i];
      time[i] = point.time;
      open[i] = point.open;
      high[i] = point.high;
      low[i] = point.low;
      close[i] = point.close;
      volume[i] = point.volume;
    }

    return { time, open, high, low, close, volume };
  }
}
