// ── OhlcvBar / OhlcvTuple / OhlcvInput ────────────────────────────────────

/** TradingView LWC 互換 Object 形式 — 推奨 */
export interface OhlcvBar {
  time:    number;   // UNIX seconds (LWC 互換) or milliseconds (Highcharts, 自動判定)
  open:    number;
  high:    number;
  low:     number;
  close:   number;
  volume?: number;   // optional — LWC は volume を別シリーズとして扱うため省略可 (default: 0)
}

/** Highcharts 互換 Tuple 形式 [time, open, high, low, close, volume?] */
export type OhlcvTuple = [
  time:    number,   // UNIX ms or seconds (自動判定)
  open:    number,
  high:    number,
  low:     number,
  close:   number,
  volume?: number,
];

/** setData() の入力型 — Object[] と Tuple[] の両方を受け付ける */
export type OhlcvInput = ReadonlyArray<OhlcvBar> | ReadonlyArray<OhlcvTuple>;

// ── IndicatorKind ─────────────────────────────────────────────────────────
// Rust IndicatorKind (u8) と 1:1 対応。as const オブジェクトで zero runtime overhead。

export const IndicatorKind = {
  SMA:             'SMA',
  EMA:             'EMA',
  BollingerBands:  'BB',
  RSI:             'RSI',
  MACD:            'MACD',
  ATR:             'ATR',
  OBV:             'OBV',
  Volume:          'Volume',
} as const;
export type IndicatorKindValue = typeof IndicatorKind[keyof typeof IndicatorKind];

// Data Worker 側で使う内部変換テーブル (JS → Rust u8)
const INDICATOR_KIND_TO_U8: Record<IndicatorKindValue, number> = {
  SMA: 0, EMA: 1, BB: 2, RSI: 3, MACD: 4, ATR: 5, OBV: 6, Volume: 7,
};

// ── RenderStyle ──────────────────────────────────────────────────────────
// Rust RenderStyle (u8) と 1:1 対応。
// 0: Line, 1: ThickLine, 2: Histogram, 3: Band
export const RenderStyle = {
  Line: 'Line',
  ThickLine: 'ThickLine',
  Histogram: 'Histogram',
  Band: 'Band',
} as const;
export type RenderStyleValue = typeof RenderStyle[keyof typeof RenderStyle];

// Data Worker 側で使う内部変換テーブル (JS → Rust u8)
const RENDER_STYLE_TO_U8: Record<RenderStyleValue, number> = {
  Line: 0,
  ThickLine: 1,
  Histogram: 2,
  Band: 3,
};

// ── PaneTarget ────────────────────────────────────────────────────────────
// Supports fixed aliases and dynamic pane labels for N-pane layouts.
export type PaneTarget = 'main' | 'sub1' | 'sub2' | `pane-${number}` | number;

// ── IndicatorConfig ───────────────────────────────────────────────────────
// Public API ↔ Data Worker 間の共通型。
// Rust ExecutionPlan.add_indicator() の引数と 1:1 対応させる。

export interface IndicatorConfig {
  kind:       IndicatorKindValue;
  period?:    number;        // SMA/EMA/RSI/ATR/BB の主期間 (default: 14)
  slow?:      number;        // MACD slow period (default: 26, requires worker-side set_macd_params mapping)
  signal?:    number;        // MACD signal period (default: 9, requires worker-side set_macd_params mapping)
  stdDev?:    number;        // BB std dev multiplier (default: 2.0, requires worker-side set_bb_params mapping)
  pane:       PaneTarget;
  style?:     RenderStyleValue; // Rust RenderStyle (default: ThickLine)
  color:      [number, number, number, number];  // RGBA [0,1] — GPU uniform 直入
  lineWidth?: number;        // px (default: 1.5)
  enabled?:   boolean;       // FLAGS bitmask の toggle 対応 (default: true)
}

// ── IndicatorHandle ───────────────────────────────────────────────────────
// addIndicator の戻り値。EP slot_id で一意識別。

export interface IndicatorHandle {
  readonly id: number;        // EP slot_id (0-63)
  applyOptions(params: Partial<IndicatorConfig>): void;
  remove(): void;
}

// ── PaneConfig ────────────────────────────────────────────────────────────
export interface PaneConfig {
  gap?: number;                    // ペイン間ギャップ px (default: renderer-defined)
  weights?: ReadonlyArray<number>; // N-pane weight array (main=weights[0])
  // Legacy fixed fields (backward compatibility)
  main?: number;
  sub1?: number;
  sub2?: number;
}

export type WorkerPostMessageOptions = Transferable[] | StructuredSerializeOptions;

export interface WorkerMessageTargetLike {
  postMessage: (message: unknown, transferOrOptions?: WorkerPostMessageOptions) => void;
  addEventListener: (type: 'message', listener: (evt: MessageEvent<unknown>) => void) => void;
}

// ── ChartApiOptions ──────────────────────────────────────────────────────────
export interface ChartApiOptions {
  renderer?:         'auto' | 'canvas' | 'canvas-worker';
  autoWorkers?:      boolean;
  renderWorkerUrl?:  string;
  dataWorkerUrl?:    string;
  width?:            number;
  height?:           number;
  dpr?:              number;
  theme?:            ThemeConfig;
  data?:             OhlcvInput;    // Object[] or Tuple[] — time 秒/ms 自動判定
  dataUrl?:          string;
  visibleBars?:      number;
  rightMarginRatio?: number;
  indicators?:       IndicatorConfig[];
  panes?:            PaneConfig;
  dataWorker?:       WorkerMessageTargetLike;
  sharedRenderWorker?: Worker;
  managerSlotId?: number;
}

export interface ThemeConfig {
  background?: string;
  upColor?:    [number, number, number, number];
  downColor?:  [number, number, number, number];
}

// ── Events ────────────────────────────────────────────────────────────────
export interface CrosshairEvent {
  barIndex: number;
  price:    number;
  time:     number;
  ohlcv:    { open: number; high: number; low: number; close: number; volume: number };
  x: number;   // CSS px
  y: number;   // CSS px
}

export interface ChartEventMap {
  crosshair:       CrosshairEvent;
  click:           CrosshairEvent;
  viewportChange:  { startBar: number; visibleBars: number; totalBars: number };
}

// ── PerfMetrics ───────────────────────────────────────────────────────────
export interface PerfMetrics {
  wasm:  { ewma: number; p50: number; p95: number };
  gpu:   { ewma: number; p50: number; p95: number };
  hud:   { ewma: number; p50: number; p95: number };
  frame: { ewma: number; p50: number; p95: number };
  mem?: {
    jsHeapUsedMB:  number;
    jsHeapTotalMB: number;
    wasmMB:        number;
  };
}

// ── Common / Annotations / Trade Records ─────────────────────────────────
export type RGBA = [number, number, number, number];

export const AnnotationType = {
  Marker: 'marker',
  HLine: 'hline',
  Zone: 'zone',
  Text: 'text',
  Event: 'event',
} as const;
export type AnnotationTypeValue = typeof AnnotationType[keyof typeof AnnotationType];

export const MarkerShape = {
  ArrowUp:   'arrow_up',
  ArrowDown: 'arrow_down',
  Circle:    'circle',
  Square:    'square',
  Label:     'label',
} as const;
export type MarkerShapeValue = typeof MarkerShape[keyof typeof MarkerShape];

export interface BaseAnnotation {
  id?: string;
  type: AnnotationTypeValue;
  pane?: PaneTarget;
  color?: RGBA;
  text?: string;
  label?: string;
  zIndex?: number;
}

export interface MarkerAnnotation extends BaseAnnotation {
  type: 'marker';
  time: number;
  price: number;
  shape: MarkerShapeValue;
  size?: number;
}

export interface HLineAnnotation extends BaseAnnotation {
  type: 'hline';
  time?: number;
  timeEnd?: number;
  price: number;
  lineWidth?: number;
  dash?: number[];
}

export interface ZoneAnnotation extends BaseAnnotation {
  type: 'zone';
  time: number;
  timeEnd: number;
  price?: number;
  priceEnd?: number;
}

export interface TextAnnotation extends BaseAnnotation {
  type: 'text';
  time: number;
  price: number;
  fontSize?: number;
  anchor?: 'bottom' | 'top' | 'center';
  bgColor?: RGBA;
}

export interface EventAnnotation extends BaseAnnotation {
  type: 'event';
  time: number;
}

export type Annotation =
  | MarkerAnnotation
  | HLineAnnotation
  | ZoneAnnotation
  | TextAnnotation
  | EventAnnotation;

export interface AnnotationHandle {
  readonly id: string;
  update(partial: Partial<Annotation>): void;
  remove(): void;
}

export interface TradeRecord {
  symbol?: string;
  entryTime: number;
  entryPrice: number;
  exitTime?: number;
  exitPrice?: number;
  stopLoss?: number;
  takeProfit?: number;
  exitReason?: string;
  pnl?: number;
  pnlPercent?: number;
  confidence?: number;
  strategy?: string;
  strategyMode?: string;
  label?: string;
}

export interface TradeRecordDisplayOptions {
  showMarkers?: boolean;
  showSlTpLines?: boolean;
  showZones?: boolean;
  showPnlLabels?: boolean;
  showConfidence?: boolean;
  entryColor?: RGBA;
  exitColor?: RGBA;
  profitZoneColor?: RGBA;
  lossZoneColor?: RGBA;
}

export interface ChartManagerOptions {
  maxCharts?: number;
  syncCrosshair?: boolean;
  syncTimeRange?: boolean;
  sharedDataWorker?: WorkerMessageTargetLike;
  createDataWorker?: () => WorkerMessageTargetLike;
  sharedRenderWorker?: Worker;
  createRenderWorker?: () => Worker;
}

export interface IChartManager {
  createChart(container: HTMLElement, chartOptions?: ChartApiOptions): IChartApi;
  destroyChart(chart: IChartApi): void;
  destroyAll(): void;
  readonly activeCount: number;
}

export interface IChartApi {
  // ── データ ──────────────────────────────────────────────────────────

  /**
   * OHLCV データを設定する（推奨 API）。
   * Object 配列 (`OhlcvBar[]`) と Tuple 配列 (`OhlcvTuple[]`) の両方を受け付ける。
   * time の単位 (秒/ミリ秒) は自動判定。volume は optional (省略時 0)。
   * API 層が内部で SoA TypedArray に自動変換 → ArrayBuffer を Data Worker へ transfer。
   * 変換後、Main Thread の JS heap にデータは残存しない。
   *
   * TradingView LWC / Highcharts / D3 からの移行がゼロコストで可能。
  * データ投入優先度は `setDataUrl()` > `setDataBinary()` > `setData()`。
   */
  setData(bars: OhlcvInput): void;

  /**
   * バイナリ SoA データを Data Worker に直接転送（上級者向け）。
   * 自前で SoA バイナリを生成済みのユーザー向けの高速パス。
   * ArrayBuffer は transfer (所有権移転) され、Main Thread の RAM 消費はゼロ。
   * フォーマット: MSFT.bin 互換 SoA バイナリ。
   */
  setDataBinary(data: ArrayBuffer): void;

  /**
   * URL を指定して Data Worker に直接 fetch させる。
   * Main Thread JS heap にデータが一切載らない最も効率的なパス。
   * バイナリ SoA フォーマットのエンドポイントを指定する。
   */
  setDataUrl(url: string): void;

  /**
   * リアルタイムティック追加。
   * Data Worker へ postMessage (transfer) で1本ずつ追加。
   * 次フレームの decompress_view_window で反映される。
   */
  appendTick(time: number, o: number, h: number, l: number, c: number, v: number): void;

  // ── ビューポート ────────────────────────────────────────────────────

  /** プログラムによるパン (正: 右 = 古いデータ方向, 負: 左 = 新しいデータ方向) */
  panByBars(deltaBars: number): void;

  /** ズーム (factor > 1: ズームアウト = バー増, centerX: CSS px) */
  zoomAt(factor: number, centerX: number): void;

  /** ビューポート直接設定 */
  setViewport(startBar: number, visibleBars: number): void;

  /**
   * 現在のビューポート状態を共有ビューで返す。
   * index: [0]=startBar, [1]=visibleBars, [2]=totalBars
   * 同一インスタンスを再利用するため、参照を長期保持せず必要なら呼び出し側でコピーすること。
   */
  getVisibleRangeView(): Int32Array;

  /**
   * 互換/デバッグ向けの snapshot object。
   * ホットパスでは `getVisibleRangeView()` を優先すること。
   */
  getVisibleRangeSnapshot(): { startBar: number; visibleBars: number; totalBars: number };

  /** @deprecated Use `getVisibleRangeView()` or `getVisibleRangeSnapshot()` instead. */
  getVisibleRange(): { startBar: number; visibleBars: number; totalBars: number };

  // ── インジケーター (Olive Execution Plan Engine) ─────────────────

  /**
   * インジケーターを追加。
   * Data Worker の ExecutionPlan.add_indicator() → compile() を駆動する。
   * 次フレームから描画に反映。戻り値の IndicatorHandle で操作可能。
   */
  addIndicator(config: IndicatorConfig): IndicatorHandle;

  /** 既存インジケーターのパラメータ変更。EP が recompile される。 */
  updateIndicator(id: number, params: Partial<IndicatorConfig>): void;

  /** インジケーター削除。EP が recompile される。 */
  removeIndicator(id: number): void;

  /** 現在のインジケーター構成を返す (read-only snapshot)。 */
  getIndicators(): readonly IndicatorConfig[];

  // ── ペイン構成 ──────────────────────────────────────────────────────

  /** ペイン比率・ギャップを変更。Render Worker へ postMessage。 */
  setPaneConfig(config: PaneConfig): void;

  // ── ライフサイクル ──────────────────────────────────────────────────

  /** DOM サイズ変更への追従 (ResizeObserver で自動、手動コールも可) */
  resize(): void;

  /**
   * 全リソース解放。
   * Worker.terminate() + SAB 参照切断 + GPU device destroy + DOM クリーンアップ。
   * 呼び出し後、このインスタンスのすべてのメソッドは no-op となる。
   */
  destroy(): void;

  // ── イベント ────────────────────────────────────────────────────────

  on<K extends keyof ChartEventMap>(event: K, cb: (e: ChartEventMap[K]) => void): void;
  off<K extends keyof ChartEventMap>(event: K, cb?: (e: ChartEventMap[K]) => void): void;

  // ── 診断 ────────────────────────────────────────────────────────────

  /** パフォーマンスメトリクス (Render Worker から最新値を取得)。 */
  // ── アノテーション (Zero-Allocation Path) ───────────────────────────
  addAnnotation(annotation: Annotation): AnnotationHandle;
  addAnnotations(annotations: Annotation[]): AnnotationHandle[];
  updateAnnotation(id: string, partial: Partial<Annotation>): void;
  removeAnnotation(id: string): void;
  getAnnotations(): readonly Annotation[];
  clearAnnotations(ids?: string[]): void;

  // ── トレードレコード (Convenience) ──────────────────────────────────
  setTradeRecords(trades: TradeRecord[], displayOptions?: TradeRecordDisplayOptions): void;
  clearTradeRecords(): void;

  getPerformanceMetrics(): PerfMetrics | null;
}
